parameters.jsCode:
// Parse the agent's plain-text output into clean JSON.
// Handles: markdown code fences, stray text before/after the JSON,
// and minor trailing-comma issues. Falls back gracefully on failure.

const item = $input.first();
let raw = item.json.output ?? item.json.text ?? '';

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

// 1. Strip markdown code fences if present (```json ... ``` or ``` ... ```)
raw = raw.replace(/```(?:json)?/gi, '').trim();

// 2. Extract the outermost JSON object: from first { to last }
const firstBrace = raw.indexOf('{');
const lastBrace = raw.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  raw = raw.slice(firstBrace, lastBrace + 1);
}

// 3. Remove trailing commas before } or ]
raw = raw.replace(/,\s*([}\]])/g, '$1');

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (err) {
  // Return a structured error so Streamlit can display something useful
  return [{
    json: {
      error: 'JSON_PARSE_FAILED',
      message: err.message,
      raw_output: item.json.output ?? item.json.text ?? ''
    }
  }];
}

// Light validation / normalization
if (!Array.isArray(parsed.competitors)) {
  parsed.competitors = [];
}
parsed.competitors = parsed.competitors.slice(0, 3);
if (parsed.industry_hint === undefined) parsed.industry_hint = null;
if (parsed.focus_area === undefined) parsed.focus_area = null;

return [{ json: parsed }];

